// function name : f_openPopUp
// function desc : 팝업
// function Parameter : Colid(컬럼명), objGrd : 그리드
//-------------------------------------------------------------------------
// f_openPopUp(columnIndex, gr_list2, "");
scwin.f_openPopUp = function (sColid, objGrd, str) {
  if (sColid == "acctCd") {
    // 계정
    // 원가
    if (ds_list2.getCellData(ds_list2.getRowPosition(), "costClsCd") == "01") {
      scwin.acctGbn = ed_regDt.getValue() + ",05";
      // 판관비
    } else if (ds_list2.getCellData(ds_list2.getRowPosition(), "costClsCd") == "02") {
      scwin.acctGbn = ed_regDt.getValue() + ",06";
      // 전체
    } else if (ds_list2.getCellData(ds_list2.getRowPosition(), "costClsCd") == "03") {
      scwin.acctGbn = ed_regDt.getValue() + ",04";
    } else {
      scwin.acctGbn = "";
    }
    let rtnList = udc_acctCdContentsInfo3.cfCommonPopUp(scwin.udc_acctCdContentsInfo3_callBackFunc, str, '', "T", null, null, null, null, scwin.acctGbn, null, null, null, null);
  } else if (sColid == "acctDeptCd") {
    // 귀속부서
    let rtnList = udc_acctDeptCdInfo2.cfCommonPopUp(scwin.udc_acctDeptCdInfo2_callBackFunc, str, '', "T", null, null, null, null, null, null, null, null, null);
  } else if (sColid == "mgntClntNo") {
    // 거래처번호
    let rtnList = udc_clntList.cfCommonPopUp(scwin.udc_clntList_callBackFunc, str // 화면에서의 ??? Code Element의  Value
    , '' // 화면에서의 ??? Name Element의  Value
    , "T" // 결과가 1건 일때  원도우를  AutoClose 여부    (T:Close,F:Opened)
    , '5' // 검색 결과    컬럼의 보여주는    개수 (SELECT절의 순서) MAX:10 - default (2)
    , null // Title순서  
    , '150,170,0,0,100' // 보여주는 각 컬럼들의 폭    
    , '3,4,6,7,8,9,10' // 컬럼중에서 숨기는    컬럼 지정   
    , null // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
    , null // POP-UP뛰을때 원도우의   사용자 정의  폭
    , null // POP-UP뛰을때 우도우의   사용자 정의  높이  
    , null // 윈도우 위치 Y좌표   
    , null // 윈도우 위치 X좌표
    , null // 중복체크여부   ("F")
    , null // 전체검색허용여부 ("F")
    , '거래처 조회,거래처코드 ,거래처명' // POP-UP Window Title 검색어1,2    ("Win타이틀,첫번검색Nm,두번?검색Nm")
    );
  } else {
    $c.win.alert($p, "Error");
  }
};

