//-------------------------------------------------------------------------
// function name : f_AcctForSetting
// function desc : 계정변경에 따른 셋팅
// function Parameter : null 
//-------------------------------------------------------------------------
scwin.f_AcctForSetting = function (dataSet, nRow) {
  // 차변이고 계정이 계정(매입 부가세) - 1111210 이면
  if (dataSet.getCellData(nRow, "drcrClsCd") == ACConstants.DEBIT && dataSet.getCellData(nRow, "acctCd") == ACConstants.ACCTCD_PCHS_VAT) {
    dataSet.setCellData(nRow, "evidClsCd", "10"); //세금계산서
    dataSet.setCellData(nRow, "deductClsCd", "1"); //공제
    dataSet.setCellData(nRow, "vatYn", "1"); // 부가세여부
    dataSet.setCellData(nRow, "taxinvcDt", scwin.strCurDate); // 세금계산서일자

    // 부가세액 관련 금액 셋팅
    for (i = 0; i < ds_list.getRowCount(); i++) {
      if (ds_list.getCellData(i, "bilgAdjmNo") == dataSet.getCellData(nRow, "bilgAdjmNo")) {
        dataSet.setCellData(nRow, "spplyAmt", ds_list.getCellData(i, "collMoneyPayAmt")); // 부가세액
      }
    }

    // 대변이고 계정이 계정(매출 부가세) - 2100710
  } else if (dataSet.getCellData(nRow, "drcrClsCd") == ACConstants.CREDIT && dataSet.getCellData(nRow, "acctCd") == ACConstants.ACCTCD_SELL_VAT) {
    dataSet.setCellData(nRow, "evidClsCd", "10"); //세금계산서
    dataSet.setCellData(nRow, "deductClsCd", "1"); //공제
    dataSet.setCellData(nRow, "vatYn", "1"); // 부가세여부
    dataSet.setCellData(nRow, "taxinvcDt", scwin.strCurDate); // 세금계산서일자

    // 부가세액 관련 금액 셋팅
    for (i = 0; i < ds_list.getRowCount(); i++) {
      if (ds_list.getCellData(i, "bilgAdjmNo") == dataSet.getCellData(nRow, "bilgAdjmNo")) {
        dataSet.setCellData(nRow, "spplyAmt", ds_list.getCellData(i, "collMoneyPayAmt")); // 부가세액
      }
    }
  } else {
    dataSet.setCellData(nRow, "evidClsCd", ""); // 그외는 증빙종류 선택 안됨!!
    dataSet.setCellData(nRow, "deductClsCd", ""); // 그외는 공제여부 선택 안됨!!
    dataSet.setCellData(nRow, "taxinvcDt", ""); // 세금계산서일자
    dataSet.setCellData(nRow, "spplyAmt", ""); // 부가세액
    dataSet.setCellData(nRow, "vatYn", "0"); // 부가세여부
  }

  // 대변이고 계정이 계정(가지급금-일반) - 1110530 이면
  if (dataSet.getCellData(nRow, "drcrClsCd") == ACConstants.CREDIT && dataSet.getCellData(nRow, "acctCd") == ACConstants.ACCTCD_PREPAY) {
    dataSet.setCellData(nRow, "adjmClsCd", ACConstants.ADJM_MTHDCD_SUSPAY); // 가지급금
  } else {
    dataSet.setCellData(nRow, "adjmClsCd", ""); // 가지급금

    // 가지금급 삭제
    for (j = ds_prov.getRowCount() - 1; j >= 0; j--) {
      if (dataSet.getCellData(nRow, "rltSeq") == ds_prov.getCellData(j, "rltSeq")) {
        ds_prov.removeRow(j);
      }
    }

    // 가지금급헤더 삭제
    for (j = ds_provHeader.getRowCount() - 1; j >= 0; j--) {
      if (dataSet.getCellData(nRow, "rltSeq") == ds_provHeader.getCellData(j, "rltSeq")) {
        ds_provHeader.removeRow(j);
      }
    }
  }

  // 지급처리여부
  // 계정이 미지급비용-거래처이고 대변일 경우 
  if ((dataSet.getCellData(nRow, "acctCd") == ACConstants.ACCTCD_PAY_COST_CLNT //미지급비용-거래처
  || dataSet.getCellData(nRow, "acctCd") == ACConstants.ACCTCD_PAY_COST_EMP //미지급비용-사원
  || dataSet.getCellData(nRow, "acctCd") == ACConstants.ACCTCD_PAY_COST_REMIT //미지급비용-송금명세
  || dataSet.getCellData(nRow, "acctCd") == ACConstants.ACCTCD_NOT_PAY //미지급금-일반
  ) && dataSet.getCellData(nRow, "drcrClsCd") == ACConstants.CREDIT) {
    dataSet.setCellData(nRow, "payProcYn", "1"); // 지급처리여부
  } else {
    dataSet.setCellData(nRow, "payProcYn", "0"); // 지급처리여부
    dataSet.setCellData(nRow, "reqPayMthdYn", "0"); // 지로여부
    dataSet.setCellData(nRow, "paymentPrd", ""); // 지로일자
  }
};

