//-------------------------------------------------------------------------
// function name : f_Prepay
// function desc : 가지급금,선급금 정리화면
// function Parameter : null
//-------------------------------------------------------------------------
scwin.f_Prepay = async function (nRow) {
  if (!(await $c.gus.cfValidate($p, [ed_regDt]))) {
    return false;
  }
  let sum = 0;
  sum = Number(ds_list2.getCellData(nRow, "crAmt"));
  var valueObject = new Object();
  valueObject.prov = ds_prov;
  valueObject.provHeader = ds_provHeader;
  valueObject.txtrltSeq = ds_list2.getCellData(nRow, "rltSeq");
  valueObject.adjmClsCd = ds_list2.getCellData(nRow, "adjmClsCd"); // 정산방법
  valueObject.sum = sum;
  valueObject.crcCd = ACConstants.KOREA_WON; // 통화코드

  let p_prov = ds_prov;
  let p_provHeader = ds_provHeader;
  let p_txtrltSeq = ds_list2.getCellData(nRow, "rltSeq");
  let p_adjmClsCd = ds_list2.getCellData(nRow, "adjmClsCd"); // 정산방법
  let p_sum = sum;
  let p_crcCd = ACConstants.KOREA_WON; // 통화코드
  let p_acctDeptCd = "";
  let p_acctDeptNm = "";

  // [수정]20051107 부서,부서명 추가
  for (j = 0; j < ds_provHeader.getRowCount(); j++) {
    if (ds_list2.getCellData(nRow, "rltSeq") == ds_provHeader.getCellData(j, "rltSeq")) {
      if (ds_provHeader.getCellData(j, "reqAcctDeptCd") != "") {
        valueObject.acctDeptCd = ds_provHeader.getCellData(j, "reqAcctDeptCd");
        valueObject.acctDeptNm = ds_provHeader.getCellData(j, "reqAcctDeptNm");
        p_acctDeptCd = ds_provHeader.getCellData(j, "reqAcctDeptCd");
        p_acctDeptNm = ds_provHeader.getCellData(j, "reqAcctDeptNm");
      }
    }
  }
  if (typeof valueObject.acctDeptCd == "undefined" || valueObject.acctDeptCd == "") {
    valueObject.acctDeptCd = ds_list2.getCellData(nRow, "acctDeptCd"); //귀속부서
    valueObject.acctDeptNm = ds_list2.getCellData(nRow, "acctDeptNm"); //귀속부서명
    p_acctDeptCd = ds_list2.getCellData(nRow, "acctDeptCd"); //귀속부서
    p_acctDeptNm = ds_list2.getCellData(nRow, "acctDeptNm"); //귀속부서명
  }
  let data = {
    valueObject: valueObject,
    prov: p_prov,
    provHeader: p_provHeader,
    txtrltSeq: p_txtrltSeq,
    adjmClsCd: p_adjmClsCd,
    acctDeptCd: p_acctDeptCd,
    acctDeptNm: p_acctDeptNm,
    sum: p_sum,
    crcCd: p_crcCd,
    compare: "1",
    flag: "Y",
    slipDt: ed_regDt.getValue().trim()
  };
  let opt = {};
  opt.width = "1500";
  opt.height = "800";
  opt.modal = true;
  opt.title = "title";
  opt.id = "popup";
  opt.popupName = "가지급금입금";

  //let strPath = "/ui/ac/fi/gnrlaccount/slipmgnt/fi_201_02_02b.xml?compare=1&flag=Y&slipDt="+ed_regDt.getValue().trim();
  let strPath = "/ui/ac/fi/gnrlaccount/slipmgnt/fi_201_02_02b.xml";
  let returnValue = await $c.win.openPopup($p, strPath, opt, data);
  if (returnValue != null) {
    ds_prov.setData(returnValue.prov.getAllJSON());
    ds_provHeader.setData(returnValue.provHeader.getAllJSON());

    // 중복된것 삭제
    for (i = 0; i < ds_prov.getRowCount() - 1; i++) {
      for (j = i + 1; j <= ds_prov.getRowCount(); j++) {
        if (ds_prov.getCellData(i, "rltSeq") == ds_prov.getCellData(j, "rltSeq")) {
          if (ds_prov.getCellData(i, "slipNo") == ds_prov.getCellData(j, "slipNo")) {
            ds_prov.removeRow(i);
            break;
          }
        }
      }
    } // for end

    for (i = 0; i < ds_provHeader.getRowCount() - 1; i++) {
      for (j = i + 1; j <= ds_provHeader.getRowCount(); j++) {
        if (ds_provHeader.getCellData(i, "rltSeq") == ds_provHeader.getCellData(j, "rltSeq")) {
          ds_provHeader.removeRow(i);
          break;
        }
      }
    } // for end
  }
};

