scwin.f_SetSupplyAmt = function (row) {
  if (ds_list2.getCellData(row, "vatYn") == "1") {
    if (ds_list2.getCellData(row, "drcrClsCd") == ACConstants.DEBIT) {
      ds_list2.setCellData(row, "spplyAmt", Math.floor(ds_list2.getCellData(row, "drAmt") * 10));
    } else {
      ds_list2.setCellData(row, "spplyAmt", Math.floor(ds_list2.getCellData(row, "crAmt") * 10));
    }
  } else {
    ds_list2.setCellData(row, "spplyAmt", 0);
  }
};

