scwin.ds_list_oncelldatachange = async function (info) {
  // 체크박스 선택 시 전표번호가 있으면 동일한 전표번호는 모두 선택되게 변경    
  if (info.colID == "chk") {
    if (!$c.gus.cfIsNull($p, ds_list.getCellData(info.rowIndex, "slipNo")) && $c.gus.cfIsNull($p, ds_list.getCellData(info.rowIndex, "reverseSlipNo"))) {
      let vChk = ds_list.getCellData(info.rowIndex, "chk");
      for (i = 0; i < ds_list.getRowCount(); i++) {
        if (ds_list.getCellData(i, "slipNo") == ds_list.getCellData(info.rowIndex, "slipNo")) {
          ds_list.setCellData(i, "chk", vChk);
        }
      }

      // 여객부문인 회계처리된 전표번호가 있고 임대/전대인 경우 관리비납입통지서 버튼을 노출한다.
      // 07 관리비(정액) 보다 클경우
      if (lc_uppermostBizdomcd.getValue() == 1 && vChk != 0 && !$c.gus.cfIsNull($p, ds_list.getCellData(info.rowIndex, "postDt")) && (ds_list.getCellData(info.rowIndex, "rentloanShapeCd") == "03" || ds_list.getCellData(info.rowIndex, "rentloanShapeCd") == "04") && ds_list.getCellData(info.rowIndex, "collMoneyPayClsCd") >= "07") {
        sMgnt.show();
        chk_printCheck.setValue(1);
        chk_previewCheck.setValue(1);
        $c.gus.cfEnableObjects($p, [btn_print]);
      } else {
        sMgnt.hide();
      }
    }

    // 전표생성과 미전표생성건을 같이 선택 못하도록 체크
    // 체크박스 선택인 것을 찾음
    let nRow = 0;
    let chk = scwin.sChk;
    for (let i = 0; i < ds_list.getRowCount(); i++) {
      if (ds_list.getCellData(i, "chk") == 1) nRow++;
    }
    if (nRow <= 0) {
      scwin.sChk = 0;
    } else {
      if ($c.gus.cfIsNull($p, ds_list.getCellData(info.rowIndex, "slipNo")) || ds_list.getCellData(info.rowIndex, "slipNo") != "" && ds_list.getCellData(info.rowIndex, "reverseSlipNo") != "") {
        scwin.sChk = 1; // 미전표번호 선택
      } else {
        scwin.sChk = 2; // 전표번호 선택
      }
    }
    if (chk == 0) {} else {
      if (chk == 1) {
        if (scwin.sChk == 2) {
          await $c.win.alert($p, "전표번호 미생성된 내역과 생성된 내역은 함께 선택불가합니다.");
          for (i = 0; i < ds_list.getRowCount(); i++) {
            if (ds_list.getCellData(i, "slipNo") == ds_list.getCellData(info.rowIndex, "slipNo")) {
              ds_list.setCellData(i, "chk", 0);
            }
          }
          scwin.sChk = 1;
          return;
        }
      } else if (chk == 2) {
        if (scwin.sChk == 1) {
          await $c.win.alert($p, "전표번호 미생성된 내역과 생성된 내역은 함께 선택불가합니다.");
          ds_list.setCellData(info.rowIndex, "chk", 0);
          scwin.sChk = 2;
          return;
        }
      } else {
        return;
      }
    }

    // 임대차[전대차] 분개내역 생성
    if ($c.gus.cfIsNull($p, ds_list.getCellData(info.rowIndex, "slipNo")) || ds_list.getCellData(info.rowIndex, "slipNo") != "" && ds_list.getCellData(info.rowIndex, "reverseSlipNo") != "") {
      if (ds_list.getCellData(info.rowIndex, "chk") == 1) {
        let sClntNo = "";
        let sMergeRentloanNo = "";
        let sRentloanShapeCd = "";
        let nCnt = 0;

        // 선택한 내역의 수금지급금액
        for (i = 0; i < ds_list.getRowCount(); i++) {
          if (ds_list.getCellData(i, "chk") == 1) {
            if (nCnt > 0 && ds_list.getCellData(i, "clntNo") != sClntNo) {
              await $c.win.alert($p, "전표를 생성하기 위해서는 동일한 거래처로 선택하여야 합니다.");
              gr_list.setFocusedCell(i, 0, false);
              scwin.nChkFlag = true;
              ds_list.setCellData(info.rowIndex, "chk", 0);
              return;
            } else {
              sClntNo = ds_list.getCellData(i, "clntNo");
            }
            if (nCnt > 0 && ds_list.getCellData(i, "mergeRentloanNo") != sMergeRentloanNo) {
              await $c.win.alert($p, "전표를 생성하기 위해서는 동일한 계약건을 선택하여야 합니다.");
              gr_list.setFocusedCell(i, 0, false);
              scwin.nChkFlag = true;
              ds_list.setCellData(info.rowIndex, "chk", 0);
              return;
            } else {
              sMergeRentloanNo = ds_list.getCellData(i, "mergeRentloanNo");
            }
            if (nCnt > 0 && ds_list.getCellData(i, "rentloanShapeCd") != sRentloanShapeCd) {
              await $c.win.alert($p, "전표를 생성하기 위해서는 동일한 계약형태를 선택하여야 합니다.");
              gr_list.setFocusedCell(i, 0, false);
              scwin.nChkFlag = true;
              ds_list.setCellData(info.rowIndex, "chk", 0);
              return;
            } else {
              sRentloanShapeCd = ds_list.getCellData(i, "rentloanShapeCd");
            }
            nCnt++;
          }
        }
        scwin.rowDoc = info.rowIndex;
        scwin.f_SlipDocList(info.rowIndex); // 전표행 생성			
      } else {
        if (scwin.nChkFlag) {
          scwin.nChkFlag = false;
          return;
        }
        scwin.f_DelSlipDocList(info.rowIndex); // 전표행 삭제
      }
    }
  }
};
