scwin.gr_list2_onviewchange = async function (info) {
  if (scwin.sFlag) {
    return;
  }
  ;
  if (info.colId == "acctCd" || info.colId == "acctDeptCd" || info.colId == "mgntClntNo") {
    scwin.f_openPopUp(info.colId, gr_list2, ds_list2.getCellData(info.rowIndex, info.colId));
  }
  if (info.colId == "drcrClsCd") {
    // 차변으로 변경시
    if (ds_list2.getCellData(info.rowIndex, "drcrClsCd") == ACConstants.DEBIT) {
      ds_list2.setCellData(info.rowIndex, "drAmt", ds_list2.getCellData(info.rowIndex, "crAmt")); // 대변 금액을 차변으로
      ds_list2.setCellData(info.rowIndex, "crAmt", 0); // 대변 0
      // 대변으로 변경시
    } else if (ds_list2.getCellData(info.rowIndex, "drcrClsCd") == ACConstants.CREDIT) {
      ds_list2.setCellData(info.rowIndex, "crAmt", ds_list2.getCellData(info.rowIndex, "drAmt")); // 차변 금액을 대변으로
      ds_list2.setCellData(info.rowIndex, "drAmt", 0); // 차변 0
    }
    scwin.f_AcctForSetting(ds_list2, info.rowIndex); // 계정변경에 따른 셋팅
  }
  if (info.colId == "summary") {
    if (info.rowIndex == 0) {
      for (i = 1; i < ds_list2.getRowCount(); i++) {
        ds_list2.setCellData(i, "summary", ds_list2.getCellData(0, "summary"));
      }
    }
  }

  // 지급처리 체크 해제 시 지로여부, 지로기간 없앰!!
  if (info.colId == "payProcYn") {
    if (ds_list2.getCellData(info.rowIndex, "payProcYn") == "0") {
      ds_list2.setCellData(info.rowIndex, "reqPayMthdYn", "0");
      ds_list2.setCellData(info.rowIndex, "paymentPrd", "");
      ds_list2.setCellData(info.rowIndex, "reqPayMthdCd", ""); // 지불방법
    } else {
      if (ds_list2.getCellData(info.rowIndex, "reqPayMthdYn") == "0") {
        ds_list2.setCellData(info.rowIndex, "reqPayMthdCd", ""); // 지불방법	
      } else {
        ds_list2.setCellData(info.rowIndex, "reqPayMthdCd", scwin.GIRO); // 지불방법
      }
    }
  }

  // 지로여부 체크 해제 시 지로기간 없앰!!
  if (info.colId == "reqPayMthdYn") {
    if (ds_list2.getCellData(info.rowIndex, "reqPayMthdYn") == "0") {
      ds_list2.setCellData(info.rowIndex, "paymentPrd", "");
      ds_list2.setCellData(info.rowIndex, "reqPayMthdCd", ""); // 지불방법
    } else {
      if (ds_list2.getCellData(info.rowIndex, "reqPayMthdYn") == "0") {
        ds_list2.setCellData(info.rowIndex, "reqPayMthdCd", ""); // 지불방법	
      } else {
        ds_list2.setCellData(info.rowIndex, "reqPayMthdCd", scwin.GIRO); // 지불방법
      }
    }
  }

  // 증빙종류 변경 시
  if (info.colId == "evidClsCd") {
    for (i = 0; i < ds_evidClsCd.getRowCount(); i++) {
      if (ds_evidClsCd.getCellData(i, "COL1") == ds_list2.getCellData(info.rowIndex, "evidClsCd")) {
        ds_list2.setCellData(info.rowIndex, "vatYn", ds_evidClsCd.getCellData(i, "COL4"));
        break;
      }
    }
  }

  // 부가세일 경우 공급가액 셋팅
  if (info.colId == "drcrClsCd" || info.colId == "acctCd" || info.colId == "evidClsCd" || info.colId == "drAmt" || info.colId == "crAmt") {
    // 차변이고 계정이 계정(매입 부가세) - 1111210 이면
    if (ds_list2.getCellData(info.rowIndex, "drcrClsCd") == ACConstants.DEBIT && ds_list2.getCellData(info.rowIndex, "acctCd") == ACConstants.ACCTCD_PCHS_VAT) {
      scwin.f_SetSupplyAmt(info.rowIndex);
    }

    // 대변이고 계정이 계정(매출 부가세) - 2100710
    if (ds_list2.getCellData(info.rowIndex, "drcrClsCd") == ACConstants.CREDIT && ds_list2.getCellData(info.rowIndex, "acctCd") == ACConstants.ACCTCD_SELL_VAT) {
      scwin.f_SetSupplyAmt(info.rowIndex);
    }

    // 대변이고 계정이 미지급비용-기타 또는 미지급비용-송금명세(2100870) 이면 입력불가 
    if (ds_list2.getCellData(info.rowIndex, "drcrClsCd") == ACConstants.CREDIT && ds_list2.getCellData(info.rowIndex, "acctCd") == ACConstants.ACCTCD_PAY_COST_REMIT) {
      await $c.win.alert($p, "대변계정에 미지급비용·송금명세(or 미지급비용·기타)계정을 입력할 수 없습니다");
      ds_list2.setCellData(info.rowIndex, "acctNm", "");
      ds_list2.setCellData(info.rowIndex, "acctCd", "");
    }
  }
};
scwin.getColumnMax = function (dataSetObj, colId) {
  let maxCol = -1;
  for (let row = 0; row < dataSetObj.getRowCount(); row++) {
    maxCol++;
  }
  return maxCol;
};
scwin.cfTabMenuAdd = function (url, name) {
  let sURL = url.split("?")[0];
  let dataString = url.split("?")[1];
  let data = {};
  let rentloanNo = "";
  let rentloanSeq = "";
  //let pgmId = $c.data.getParameter($p, "menuInfo").pgmId;

  if (dataString) {
    dataString.split("&").forEach(function (param) {
      let keyValue = param.split("=");
      let key = keyValue[0];
      let value = keyValue[1];
      data[key] = value;
      if (key == "rentloanNo") {
        rentloanNo = value;
      } else if (key == "rentloanSeq") {
        rentloanSeq = value;
      }
    });
  }
  let rentloan = rentloanNo + rentloanSeq;
  $c.win.openMenu($p, name, sURL, sURL.substring(sURL.lastIndexOf("/") + 1).replace(/.xml/g, "") + ".jsp", data, {
    menuCode: rentloan,
    menuCode2: "new"
  });
};

